-- Get SRV client ID and RRMC organization ID
SELECT @srv_client_id := id FROM clients WHERE name = 'SRV' LIMIT 1;
SELECT @rrmc_org_id := id FROM organizations WHERE slug = 'srv-rrmc' LIMIT 1;

-- Create test users for SRV client
INSERT INTO users (email, password, name, role, clientId, organizationId, createdAt, updatedAt)
VALUES 
  ('test.srv1@example.com', '$2b$10$abcdefghijklmnopqrstuv', 'SRV Test User 1', 'user', @srv_client_id, @rrmc_org_id, NOW(), NOW()),
  ('test.srv2@example.com', '$2b$10$abcdefghijklmnopqrstuv', 'SRV Test User 2', 'user', @srv_client_id, @rrmc_org_id, NOW(), NOW());

-- Verify the users were created
SELECT id, email, clientId, organizationId FROM users WHERE clientId = @srv_client_id;

